 {"id":"bd-160","title":"Implement migration file generator","description":"# Task: Implement Migration File Generator

## Context
The migration file generator takes schema diffs and DDL statements and writes them to version-controlled migration files that can be executed in order.

## Design Goals
1. **Timestamped versions**: Unique, orderable migration IDs
2. **Up/Down migrations**: Both forward and rollback DDL
3. **Human-readable**: Formatted SQL with comments
4. **Tracking table**: Record which migrations have been applied

## What to Implement

### 1. Migration File Structure
\`\`\`
migrations/
├── 20260127120000_create_heroes_table.rs    # or .sql
├── 20260127120100_add_team_id_to_heroes.rs
└── 20260127120200_create_powers_table.rs
\`\`\`

### 2. Migration Struct
\`\`\`rust
/// A database migration with up/down operations.
#[derive(Debug, Clone)]
pub struct Migration {
    /// Unique version identifier (timestamp-based)
    pub version: String,
    /// Human-readable description
    pub description: String,
    /// Forward migration SQL statements
    pub up: Vec<String>,
    /// Rollback migration SQL statements
    pub down: Vec<String>,
    /// Timestamp when migration was created
    pub created_at: chrono::DateTime<chrono::Utc>,
}

impl Migration {
    /// Generate version from current timestamp.
    pub fn new_version() -> String {
        chrono::Utc::now().format("%Y%m%d%H%M%S").to_string()
    }

    /// Create from schema diff.
    pub fn from_diff(diff: &SchemaDiff, ddl: &impl DdlGenerator, description: &str) -> Self {
        let version = Self::new_version();
        let up = ddl.generate_all(&diff.ops);
        let down = ddl.generate_rollback(&diff.ops);

        Self {
            version,
            description: description.to_string(),
            up,
            down,
            created_at: chrono::Utc::now(),
        }
    }
}
\`\`\`

### 3. Migration Writer
\`\`\`rust
/// Writes migrations to the filesystem.
pub struct MigrationWriter {
    /// Directory for migration files
    pub migrations_dir: PathBuf,
    /// File format (sql or rs)
    pub format: MigrationFormat,
}

#[derive(Debug, Clone, Copy)]
pub enum MigrationFormat {
    /// Plain SQL files
    Sql,
    /// Rust source files
    Rust,
}

impl MigrationWriter {
    pub fn new(dir: impl Into<PathBuf>) -> Self {
        Self {
            migrations_dir: dir.into(),
            format: MigrationFormat::Sql,
        }
    }

    pub fn with_format(mut self, format: MigrationFormat) -> Self {
        self.format = format;
        self
    }

    /// Write a migration to disk.
    pub fn write(&self, migration: &Migration) -> std::io::Result<PathBuf> {
        std::fs::create_dir_all(&self.migrations_dir)?;

        let filename = self.filename(migration);
        let path = self.migrations_dir.join(&filename);
        let content = self.format_migration(migration);

        std::fs::write(&path, content)?;

        Ok(path)
    }

    fn filename(&self, m: &Migration) -> String {
        let sanitized_desc = m.description
            .to_lowercase()
            .replace(' ', "_")
            .replace(|c: char| !c.is_alphanumeric() && c != '_', "");

        match self.format {
            MigrationFormat::Sql => format!("{}_{}.sql", m.version, sanitized_desc),
            MigrationFormat::Rust => format!("{}_{}.rs", m.version, sanitized_desc),
        }
    }

    fn format_migration(&self, m: &Migration) -> String {
        match self.format {
            MigrationFormat::Sql => self.format_sql(m),
            MigrationFormat::Rust => self.format_rust(m),
        }
    }

    fn format_sql(&self, m: &Migration) -> String {
        let mut content = String::new();

        // Header
        content.push_str(&format!("-- Migration: {}\n", m.description));
        content.push_str(&format!("-- Version: {}\n", m.version));
        content.push_str(&format!("-- Created: {}\n\n", m.created_at.to_rfc3339()));

        // Up migration
        content.push_str("-- ====== UP ======\n\n");
        for stmt in &m.up {
            content.push_str(stmt);
            content.push_str(";\n\n");
        }

        // Down migration
        content.push_str("-- ====== DOWN ======\n\n");
        for stmt in &m.down {
            content.push_str("-- ");
            content.push_str(stmt);
            content.push_str(";\n\n");
        }

        content
    }

    fn format_rust(&self, m: &Migration) -> String {
        // Generate Rust code that returns the migration
        // ...
    }
}
