### 4. Migration Runner
\`\`\`rust
/// Executes migrations against a database.
pub struct MigrationRunner<'c> {
    conn: &'c mut dyn Connection,
    migrations_table: &'static str,
}

impl<'c> MigrationRunner<'c> {
    pub fn new(conn: &'c mut dyn Connection) -> Self {
        Self {
            conn,
            migrations_table: "_sqlmodel_migrations",
        }
    }

    /// Ensure the migrations tracking table exists.
    pub async fn ensure_schema(&mut self) -> Result<()> {
        let sql = format!(
            "CREATE TABLE IF NOT EXISTS {} (
                version VARCHAR(20) PRIMARY KEY,
                description TEXT NOT NULL,
                applied_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
            )",
            self.migrations_table
        );
        self.conn.execute(&sql, &[]).await?;
        Ok(())
    }

    /// Get list of applied migrations.
    pub async fn applied(&self) -> Result<Vec<String>> {
        let sql = format!(
            "SELECT version FROM {} ORDER BY version",
            self.migrations_table
        );
        let rows = self.conn.fetch_all(&sql, &[]).await?;
        Ok(rows.iter().map(|r| r.get("version")).collect())
    }

    /// Apply a migration.
    pub async fn apply(&mut self, migration: &Migration) -> Result<()> {
        // Execute each up statement
        for stmt in &migration.up {
            self.conn.execute(stmt, &[]).await?;
        }

        // Record in tracking table
        let sql = format!(
            "INSERT INTO {} (version, description) VALUES (?, ?)",
            self.migrations_table
        );
        self.conn.execute(&sql, &[
            Value::String(migration.version.clone()),
            Value::String(migration.description.clone()),
        ]).await?;

        Ok(())
    }

    /// Rollback a migration.
    pub async fn rollback(&mut self, migration: &Migration) -> Result<()> {
        // Execute each down statement
        for stmt in &migration.down {
            self.conn.execute(stmt, &[]).await?;
        }

        // Remove from tracking table
        let sql = format!(
            "DELETE FROM {} WHERE version = ?",
            self.migrations_table
        );
        self.conn.execute(&sql, &[Value::String(migration.version.clone())]).await?;

        Ok(())
    }

    /// Run all pending migrations.
    pub async fn migrate(&mut self, migrations: &[Migration]) -> Result<MigrateResult> {
        let applied = self.applied().await?;
        let pending: Vec<_> = migrations.iter()
            .filter(|m| !applied.contains(&m.version))
            .collect();

        let mut result = MigrateResult { applied: 0, skipped: applied.len() };

        for migration in pending {
            self.apply(migration).await?;
            result.applied += 1;
        }

        Ok(result)
    }
}

#[derive(Debug)]
pub struct MigrateResult {
    pub applied: usize,
    pub skipped: usize,
}
