## Rust Implementation

```rust
pub trait SessionEvents {
    fn before_flush(&mut self, new: &[&dyn Model], dirty: &[&dyn Model], deleted: &[&dyn Model]) 
        -> Result<(), Error> { Ok(()) }
    fn after_flush(&mut self) -> Result<(), Error> { Ok(()) }
    fn before_commit(&mut self) -> Result<(), Error> { Ok(()) }
    fn after_commit(&mut self) -> Result<(), Error> { Ok(()) }
    fn after_rollback(&mut self) -> Result<(), Error> { Ok(()) }
}
